// 2D 网格三角剖分示例
// 将一个矩形精灵分割为 2x2 的三角网格
interface Vertex {
  x: number;  // 顶点位置
  y: number;
  u: number;  // UV 坐标
  v: number;
  boneIndices: number[];  // 骨骼索引
  boneWeights: number[];  // 骨骼权重
}

// 4 个顶点，2 个三角形
const vertices: Vertex[] = [
  { x: 0, y: 0, u: 0, v: 0, boneIndices: [0], boneWeights: [1] },
  { x: 1, y: 0, u: 1, v: 0, boneIndices: [0, 1], boneWeights: [0.5, 0.5] },
  { x: 1, y: 1, u: 1, v: 1, boneIndices: [1], boneWeights: [1] },
  { x: 0, y: 1, u: 0, v: 1, boneIndices: [0, 1], boneWeights: [0.5, 0.5] },
];
const indices = [0, 1, 2, 0, 2, 3]; // 两个三角形

// CCD IK 算法
function solveCCD(
  bones: Bone[],     // 骨骼链
  target: Vec2,      // 目标位置
  iterations: number // 迭代次数
) {
  const endEffector = bones[bones.length - 1];

  for (let iter = 0; iter < iterations; iter++) {
    // 从末端向根部遍历
    for (let i = bones.length - 2; i >= 0; i--) {
      const bone = bones[i];
      const endPos = getEndEffectorPos(bones);

      // 计算从骨骼到末端和从骨骼到目标的向量
      const toEnd = Vec2.sub(endPos, bone.worldPos);
      const toTarget = Vec2.sub(target, bone.worldPos);

      // 计算需要旋转的角度
      const angle = Vec2.signedAngle(toEnd, toTarget);

      // 应用旋转（限制范围）
      bone.rotation += clamp(angle, -maxDelta, maxDelta);
      updateWorldTransforms(bones);

      // 如果末端足够接近目标，提前退出
      if (Vec2.distance(endPos, target) < threshold) return;
    }
  }
}

// FABRIK IK 算法
function solveFABRIK(
  bones: Bone[],
  target: Vec2,
  iterations: number
) {
  const rootPos = bones[0].worldPos.clone();
  const distances: number[] = [];

  // 计算每段骨骼长度
  for (let i = 0; i < bones.length - 1; i++) {
    distances[i] = Vec2.distance(bones[i].worldPos, bones[i+1].worldPos);
  }

  for (let iter = 0; iter < iterations; iter++) {
    // 前向阶段：从末端到根部
    bones[bones.length-1].worldPos = target.clone();
    for (let i = bones.length - 2; i >= 0; i--) {
      const dir = Vec2.normalize(
        Vec2.sub(bones[i].worldPos, bones[i+1].worldPos)
      );
      bones[i].worldPos = Vec2.add(
        bones[i+1].worldPos,
        Vec2.scale(dir, distances[i])
      );
    }

    // 后向阶段：从根部到末端
    bones[0].worldPos = rootPos.clone();
    for (let i = 0; i < bones.length - 1; i++) {
      const dir = Vec2.normalize(
        Vec2.sub(bones[i+1].worldPos, bones[i].worldPos)
      );
      bones[i+1].worldPos = Vec2.add(
        bones[i].worldPos,
        Vec2.scale(dir, distances[i])
      );
    }

    if (Vec2.distance(bones[bones.length-1].worldPos, target) < threshold) break;
  }

  // 从世界位置反算旋转
  for (let i = 0; i < bones.length - 1; i++) {
    bones[i].rotation = Math.atan2(
      bones[i+1].worldPos.y - bones[i].worldPos.y,
      bones[i+1].worldPos.x - bones[i].worldPos.x
    );
  }
}

// 两段骨骼 IK 解析解
// 骨骼 A (上臂) 长度 L1, 骨骼 B (前臂) 长度 L2
// 目标位置 T, 肩部位置 S
function solveTwoBoneIK(
  shoulder: Vec2,   // 肩部位置
  target: Vec2,     // 目标位置
  L1: number,       // 上臂长度
  L2: number,       // 前臂长度
  bendDir: number   // 弯曲方向 (1 或 -1)
): { elbowAngle: number; shoulderAngle: number } {
  // 目标到肩部的距离
  const dx = target.x - shoulder.x;
  const dy = target.y - shoulder.y;
  const dist = Math.sqrt(dx*dx + dy*dy);

  // 限制目标在可达范围内
  const clampedDist = Math.min(dist, L1 + L2 - 0.001);
  const clampedDist2 = Math.max(clampedDist, Math.abs(L1 - L2) + 0.001);

  // 使用余弦定理求肘部角度
  // cos(elbow) = (L1^2 + L2^2 - dist^2) / (2*L1*L2)
  const cosElbow = (L1*L1 + L2*L2 - clampedDist2*clampedDist2) / (2*L1*L2);
  const elbowAngle = Math.acos(clamp(cosElbow, -1, 1)) * bendDir;

  // 求肩部角度
  const cosAlpha = (L1*L1 + clampedDist2*clampedDist2 - L2*L2) / (2*L1*clampedDist2);
  const alpha = Math.acos(clamp(cosAlpha, -1, 1));
  const beta = Math.atan2(dy, dx);
  const shoulderAngle = beta - alpha * bendDir;

  return { elbowAngle, shoulderAngle };
}
